import{_ as t}from"./chunks/mobile_ai.CxgTVI8g.js";import{_ as o,c as a,o as i,a1 as n}from"./chunks/framework.DDNAyvCW.js";const s="/assets/mobile_ai_chat.DsIDWcjy.jpg",r="/assets/mobile_ai_term.BDCCvl8M.jpg",l="/assets/mobile_ai_history.BwyyMjjZ.jpg",c="/assets/mobile_ai_chat_approve.BfQzgcJ4.jpg",d="/assets/mobile_ai_chat_command_parse.CsHP7wkq.jpg",p="/assets/mobile_ai_chat_voice.BqcXm7G7.jpg",h="/assets/mobile_ai_chat_voice_correct.hfZaAhkP.jpg",_=JSON.parse('{"title":"AI Dialog","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/ai-agent/index.md","filePath":"docs/mobile/ai-agent/index.md"}'),m={name:"docs/mobile/ai-agent/index.md"};function u(g,e,b,f,y,v){return i(),a("div",null,e[0]||(e[0]=[n('<h1 id="ai-dialog" tabindex="-1">AI Dialog <a class="header-anchor" href="#ai-dialog" aria-label="Permalink to &quot;AI Dialog&quot;">​</a></h1><p>AI Session is a core capability of Chaterm&#39;s mobile app. It lets you handle server issues from your phone anytime, anywhere — not just executing commands, but with AI actively helping you think, troubleshoot, and make decisions.</p><p>Whether you receive an alert on the subway, need to debug urgently while traveling, or aren&#39;t sure how to write a command, you can describe the problem in plain language and let AI analyze, suggest, and execute. Voice input frees your hands further, and seamless switching between Terminal and Chat keeps context always connected.</p><p>The mobile app provides two main modes: <code>Chat</code> and <code>Term</code>. You can switch between them from the mode selector below the input box.</p><div class="tip custom-block"><p class="custom-block-title">Prerequisites</p><p>Before using AI features (Chat mode, voice correction, command explanation), sign in and configure a model in <a href="/docs/mobile/profile/#model-selection">Profile &gt; AI Settings &gt; Model Selection</a>.</p></div><div style="text-align:center;"><img src="'+t+'" alt="AI Dialog mobile page" width="320"></div><h2 id="chat-mode" tabindex="-1">Chat Mode <a class="header-anchor" href="#chat-mode" aria-label="Permalink to &quot;Chat Mode&quot;">​</a></h2><p><code>Chat</code> mode is designed for working with AI on analysis, explanations, and command suggestions.</p><p>Supports text and voice input. AI can parse natural language to generate commands and continue troubleshooting based on context.</p><p>Best for: learning Linux commands, troubleshooting, writing scripts, understanding configuration files, and reviewing operations best practices.</p><div style="text-align:center;"><img src="'+s+'" alt="AI Dialog chat mode" width="320"></div><h2 id="term-mode" tabindex="-1">Term Mode <a class="header-anchor" href="#term-mode" aria-label="Permalink to &quot;Term Mode&quot;">​</a></h2><p><code>Term</code> mode directly executes commands without sending them through AI.</p><p>Connect to a server first. If no server is connected, the page shows an entry to connect a host. Supports text and voice input, and returns command output directly.</p><p>Best for: running a quick one-off command, checking host status fast.</p><div style="text-align:center;"><img src="'+r+'" alt="AI Dialog term mode" width="320"></div><h2 id="context-sharing" tabindex="-1">Context Sharing <a class="header-anchor" href="#context-sharing" aria-label="Permalink to &quot;Context Sharing&quot;">​</a></h2><p>A common pain point when troubleshooting on mobile: you run a command, see the output, want to ask AI what it means — but you have to manually select text, copy it, switch to the input box, and paste. On a small phone screen, this is tedious. Worse, if the output is long, it&#39;s nearly impossible to select it all.</p><p>Our solution is to have both modes share the same session context. Commands executed in Term mode and their output are directly visible to AI when you switch to Chat mode — no copy-paste needed.</p><p><strong>Typical scenario:</strong></p><ol><li>In <strong>Term mode</strong>, run a command such as <code>journalctl -n 50</code> and see the log output</li><li>Switch to <strong>Chat mode</strong></li><li>Type &quot;Help me analyze the errors above&quot;</li><li>AI analyzes the output directly without needing any copy-paste</li></ol><p>This also applies to other scenarios, for example: run <code>df -h</code> and ask &quot;Which partition is almost full?&quot;, or run your own script <code>xxx.js</code> and ask &quot;What&#39;s the current task progress?&quot;.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Switching modes does not clear the context. All terminal output from the current session is visible to AI.</p></div><h2 id="history-sessions" tabindex="-1">History Sessions <a class="header-anchor" href="#history-sessions" aria-label="Permalink to &quot;History Sessions&quot;">​</a></h2><p>Tap the icon in the upper-left corner to open the chat history sidebar and view all previous sessions. You can tap or long-press a session to perform more actions, such as favoriting sessions you find important.</p><h3 id="actions" tabindex="-1">Actions: <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions:&quot;">​</a></h3><ul><li><strong>Switch session</strong>: tap any history entry to switch to that session</li><li><strong>New session</strong>: tap the new button at the top of the sidebar to start a fresh session</li><li><strong>Edit title</strong>: long-press a session entry and choose <code>Edit</code> to rename it</li><li><strong>Favorite session</strong>: long-press a session entry to favorite it; favorited sessions appear at the top of the list</li><li><strong>Delete sessions</strong>: long-press to enter multi-select mode and batch-delete history entries</li></ul><div style="text-align:center;"><img src="'+l+'" alt="Chat history" width="320"></div><h2 id="command-approval" tabindex="-1">Command Approval <a class="header-anchor" href="#command-approval" aria-label="Permalink to &quot;Command Approval&quot;">​</a></h2><p>In <code>Chat</code> mode, AI pauses before executing a command and waits for your confirmation by default (approval mode). You can enable <strong>Auto-execute</strong> in <a href="/docs/mobile/profile/#ai-preferences">Profile &gt; AI Preferences</a> to let commands run without approval.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Approval mode</strong> (default)</td><td>Pauses before each command and shows Approve / Reject buttons</td></tr><tr><td><strong>Auto-execute mode</strong></td><td>Commands run automatically without confirmation</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">Danger</p><p>In auto-execute mode, AI may run multiple commands in succession without individual confirmation. Enable this only for familiar tasks or when you are confident about what the AI will do.</p></div><div style="text-align:center;"><img src="'+c+'" alt="Command approval" width="320"></div><h2 id="command-explanation" tabindex="-1">Command Explanation <a class="header-anchor" href="#command-explanation" aria-label="Permalink to &quot;Command Explanation&quot;">​</a></h2><p>In approval mode, when AI shows a pending command, you can tap the <strong>Explain</strong> icon to view command details — in addition to the Approve and Reject buttons.</p><p><strong>Button reference:</strong></p><table tabindex="0"><thead><tr><th>Button</th><th>Description</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Confirm and run the command</td></tr><tr><td><strong>Reject</strong></td><td>Cancel execution; AI stops the current task</td></tr><tr><td><strong>Explain</strong> (document icon)</td><td>Opens a bottom panel where AI streams an explanation of the command</td></tr></tbody></table><p><strong>Explanation panel:</strong></p><p>After tapping the explain icon, the bottom sheet displays a step-by-step breakdown in real time, including:</p><ul><li>The overall purpose and safety of the command</li><li>What each argument does</li><li>Any potential side effects or caveats</li></ul><p>Viewing an explanation does not trigger execution — you can safely review it before deciding to approve.</p><div style="text-align:center;"><img src="'+d+'" alt="Command explanation" width="320"></div><h2 id="chat-voice-input" tabindex="-1">Chat Voice Input <a class="header-anchor" href="#chat-voice-input" aria-label="Permalink to &quot;Chat Voice Input&quot;">​</a></h2><p>Both Chat and Term modes support voice input. Tap the microphone icon to the right of the input box to switch to voice input.</p><p><strong>How to use:</strong></p><ol><li>Tap the microphone icon — the input box switches to a voice input button</li><li><strong>Long-press</strong> the voice button to start recording; release to auto-transcribe</li><li>Slide up before releasing to cancel the recording</li><li>After transcription, the text is sent automatically (Chat mode)</li></ol><div style="text-align:center;"><img src="'+p+'" alt="Voice input" width="320"></div><h2 id="voice-command-input" tabindex="-1">Voice Command Input <a class="header-anchor" href="#voice-command-input" aria-label="Permalink to &quot;Voice Command Input&quot;">​</a></h2><p>In <strong>Term mode</strong>, voice recognition results are automatically corrected by AI and filled into the input box. Through fine-tuning of our voice model, we achieve precise recognition of SRE domain commands, eliminating the need to type commands on a mobile keyboard. For example:</p><ul><li>Say &quot;kube ctl get po&quot; → auto-corrected to <code>kubectl get pods</code></li><li>Say &quot;docker dash a&quot; → auto-corrected to <code>docker ps -a</code></li></ul><div style="text-align:center;"><img src="'+h+'" alt="Voice correction" width="320"></div><h2 id="typical-workflow" tabindex="-1">Typical Workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical Workflow&quot;">​</a></h2><ol><li>Open the AI dialog page</li><li>Connect to the target host</li><li>Choose <code>Chat</code> or <code>Term</code></li><li>Enter a question or command, or start a request with voice input</li><li>Review the result and continue if needed</li></ol><h2 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h2><ul><li>Use <code>Chat</code> mode first when you need explanation, planning, or troubleshooting</li><li>Before running an unfamiliar command, tap <strong>Explain</strong> to understand what it does before approving</li></ul>',55)]))}const A=o(m,[["render",u]]);export{_ as __pageData,A as default};
